public List<List<Integer>> criticalConnections(int n, List<List<Integer>> connections) {
    List<Integer>[] adj = new ArrayList[n];
    for (int i = 0; i < n; i++) adj[i] = new ArrayList<>();
    for (List<Integer> c : connections) {
        adj[c.get(0)].add(c.get(1)); adj[c.get(1)].add(c.get(0));
    }
    int[] tin = new int[n], low = new int[n];
    Arrays.fill(tin, -1);
    List<List<Integer>> bridges = new ArrayList<>();
    dfs(0, -1, adj, tin, low, bridges);
    return bridges;
}
private void dfs(int u, int p, List<Integer>[] adj, int[] tin, int[] low, List<List<Integer>> bridges) {
    tin[u] = low[u] = timer++;
    for (int v : adj[u]) {
        if (v == p) continue;
        if (tin[v] == -1) {
            dfs(v, u, adj, tin, low, bridges);
            low[u] = Math.min(low[u], low[v]);
            if (low[v] > tin[u]) bridges.add(Arrays.asList(u, v));
        } else low[u] = Math.min(low[u], tin[v]);
    }
}

