private void backtrack(List<String> res, String path, String num, int target, int pos, long val, long prev) {
    if (pos == num.length()) {
        if (val == target) res.add(path);
        return;
    }
    for (int i = pos; i < num.length(); i++) {
        if (i != pos && num.charAt(pos) == '0') break;
        long curr = Long.parseLong(num.substring(pos, i + 1));
        if (pos == 0) backtrack(res, "" + curr, num, target, i + 1, curr, curr);
        else {
            backtrack(res, path + "+" + curr, num, target, i + 1, val + curr, curr);
            backtrack(res, path + "-" + curr, num, target, i + 1, val - curr, -curr);
            backtrack(res, path + "*" + curr, num, target, i + 1, val - prev + prev * curr, prev * curr);
        }
    }
}

