struct DSU { 
    std::vector<int> parent;
    DSU(int n) { for(int i=0; i<n; i++) parent.push_back(i); }
    int find(int i) { return (parent[i] == i) ? i : (parent[i] = find(parent[i])); }
    void unite(int i, int j) { int root_i = find(i); int root_j = find(j); if(root_i != root_j) parent[root_i] = root_j; }
};

int kruskal(int n, std::vector<Edge>& edges) {
    std::sort(edges.begin(), edges.end(), [](Edge a, Edge b) { return a.w < b.w; });
    DSU dsu(n); int mst_weight = 0;
    for(auto& e : edges) {
        if(dsu.find(e.u) != dsu.find(e.v)) {
            dsu.unite(e.u, e.v);
            mst_weight += e.w;
        }
    }
    return mst_weight;
}

